arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0 and life>0
  {
    if initDir=0
    {
      xVel=runAcc
      if x>oPlayer1.x
        xVel*=-1
      initDir=1
    }
    
    if turnTime<=30
    {
      if x>oPlayer1.x and image_xscale=1
        turnTime+=1
      else if x<oPlayer1.x and image_xscale=-1
        turnTime+=1
      
      if !isCollisionBottom(1) and turnTime=31 {turnTime=29}
    }
    else
    {
      turnTime+=1
      if turnTime=32 {sprite_index=sRushRoaderTurn}
      else if turnTime>=41
      {
        sprite_index=sRushRoaderRide
        xVel*=-1
        turnTime=0
      }
    }
    
    if !isCollisionBottom(1)
      yVel+=0.2
    if isCollisionSolid()
      y-=2
    
    if xVel>0
      image_xscale=1
    else
      image_xscale=-1
    
    enemySlopeMovement()
    
    if y>room_height+24
    {
      if questType>0
        enemyQuest(questType)
      instance_destroy()
    }
  }
  else if life<=0
  {
    playSound(global.snd_EnemyDieMM,0,1,1)
    tEffect=instance_create(x,y-12,oEffect)
    tEffect.sprite_index=sMMExplosion
    tEffect.newBlend=-1; tEffect.followID=-1; tEffect.decay=-100; tEffect.xSpd=0; tEffect.ySpd=0
    instance_destroy()
  }
  enemyStepEvent()
}
